INSERT INTO `bot_responses` (`id`, `keyword`, `menu_label`, `response`, `is_exact_match`, `is_menu`, `parent_id`, `sort_order`, `group_enabled`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'menu,help,bantuan,hi,halo,hai,hello,admin,cs,mulai,start', '🏠 MENU UTAMA ROZITECH', 'Halo! Saya R-Care, Customer Service AI resmi dari Rozitech 👋\n\nSilakan pilih layanan kami di bawah ini:\n\n1️⃣ Layanan WiFi (Internet)\n2️⃣ Jasa IT (Web & App)\n3️⃣ Layanan Aplikasi Casir\n4️⃣ Info Kantor & Pembayaran\n\nAtau ketik langsung kebutuhan Anda, kami siap membantu 😊', 0, 1, NULL, 1, 1, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(2, '1', '📶 LAYANAN WIFI (INTERNET)', 'Pilih layanan WiFi yang Anda butuhkan:\n\n1. Ketik *paket wifi* — Lihat daftar paket & harga\n2. Ketik *pasang wifi* — Formulir pasang baru\n3. Ketik *lapor* — Lapor gangguan internet\n4. Ketik *cek tagihan* — Cek tagihan Anda', 1, 1, 1, 1, 1, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(3, 'cek tagihan', 'Tagihan Wifi — Contoh: Cek Tagihan aa20', '{cek_tagihan}', 0, 0, 2, 5, 1, 1, '2026-05-04 01:35:10', '2026-05-04 02:09:20'),
(4, 'paket wifi,harga internet,harga wifi,daftar paket', '📋 Daftar Paket & Harga', 'Halo! Berikut pilihan paket Rozitech WiFi (Tanpa FUP):\n\n1. Paket 10 Mbps : Rp 150.000 / bulan\n2. Paket 20 Mbps : Rp 250.000 / bulan\n3. Paket 30 Mbps : Rp 350.000 / bulan\n\n📦 Biaya Pasang: Rp 250.000\n(Sudah termasuk 2 bulan internet 10 Mbps)\n\nMinat pasang? Ketik *pasang wifi* untuk formulir pendaftaran 😊', 0, 0, 2, 2, 1, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(5, 'pasang wifi,formulir wifi,daftar wifi,instalasi wifi,pasang baru,berlangganan,pemasangan', '📝 Formulir Pasang Baru', 'Terima kasih atas minat Anda! 🎉\nBerikut formulir pendaftaran pemasangan internet baru:\n\n━━━━━━━━━━━━━━━━━━━━━━\nFORMULIR PASANG BARU WIFI (PSB WIFI)\n━━━━━━━━━━━━━━━━━━━━━━\nNAMA         :\nALAMAT       :\nNO HP        :\nSHARE LOKASI :\nFOTO RUMAH   :\nFOTO KTP     :\n━━━━━━━━━━━━━━━━━━━━━━\n\n📌 Catatan:\n1. Paket pemasangan sudah termasuk 2 bulan speed 10 Mbps.\n2. Langganan minimal 6 bulan dari masa pendaftaran. Jika berhenti sebelum 6 bulan, dikenakan denda Rp 200.000.\n3. Kami berhak mengambil alat jika pelanggan tidak membayar lebih dari 2 bulan.\n\nJika setuju, silakan isi formulir di atas agar tim teknisi kami bisa menjadwalkan pemasangan segera 🙏', 0, 0, 2, 3, 1, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(6, 'lapor,gangguan,internet mati,wifi mati,tidak ada koneksi,internet putus,modem merah,lampu merah,los merah,sinyal mati', '🛠️ Lapor Gangguan (Mati/Lemot)', 'Mohon maaf atas ketidaknyamanannya kak 🙏\n\nSilakan coba langkah awal berikut:\n✅ Cek lampu modem — pastikan tidak ada lampu LOS yang merah.\n✅ Cabut adaptor modem dari listrik, tunggu 30–60 detik, lalu pasang kembali.\n✅ Tunggu hingga modem menyala normal (sekitar 2–3 menit).\n\nJika setelah dicoba internet masih bermasalah, mohon informasikan:\n📋 Nama pelanggan / ID pelanggan\n📍 Alamat & share lokasi\n📸 Foto lampu indikator modem saat ini\n\nKami akan segera hubungkan ke tim teknisi untuk penanganan lebih lanjut 🔧', 0, 0, 2, 4, 1, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(7, '2', '💻 JASA IT (WEB & APP)', 'Rozitech melayani pembuatan Website dan Aplikasi Custom:\n\n🌐 Ketik *web* — Harga & info pembuatan website\n📱 Ketik *app* — Harga & info pembuatan aplikasi', 1, 1, 1, 2, 1, 1, '2026-05-04 01:35:10', '2026-05-04 01:35:10'),
(8, 'web,website,bikin website,buat website,harga website', '🌐 Harga Pembuatan Website', '💰 DAFTAR HARGA WEBSITE ROZITECH 💰\n\n1. Website Profil Bisnis : Mulai Rp 1.500.000\n2. Toko Online           : Mulai Rp 3.000.000\n3. Custom Web System     : Hubungi admin untuk konsultasi\n\nInfo lebih lanjut? Ketik *admin* atau hubungi CS kami 😊', 0, 0, 7, 1, 1, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(9, 'app,aplikasi,bikin aplikasi,buat aplikasi,harga aplikasi', '📱 Harga Pembuatan Aplikasi', '📱 CUSTOM APP DEVELOPMENT — ROZITECH 📱\n\nAndroid / iOS Apps: Mulai Rp 5.000.000\n(Harga menyesuaikan tingkat kerumitan fitur)\n\nUntuk konsultasi kebutuhan fitur & estimasi biaya, silakan hubungi admin kami langsung 😊', 0, 0, 7, 2, 1, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(10, '3', '📖 LAYANAN APLIKASI CASIR', 'Layanan support untuk pengguna aplikasi Casir:\n\n🚀 Ketik *download* — Link download aplikasi\n📘 Ketik *tutorial* — Panduan penggunaan Casir', 1, 1, 1, 3, 1, 1, '2026-05-04 01:35:10', '2026-05-04 01:35:10'),
(11, 'download,unduh,unduh casir,download casir,install casir', '🚀 Download Aplikasi Casir', '🚀 DOWNLOAD & INSTALL APLIKASI CASIR\n\n📲 Klik link berikut untuk mengunduh:\nhttps://bit.ly/download-casir-app\n\nJika ada kendala saat instalasi, silakan ketik *tutorial* atau hubungi admin kami 😊', 0, 0, 10, 1, 1, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(12, 'tutorial,panduan,cara pakai,petunjuk casir,cara menggunakan casir', '📘 Panduan Penggunaan', '📖 PANDUAN PENGGUNAAN APLIKASI CASIR\n\nUntuk panduan lengkap, silakan akses video tutorial kami di:\n🔗 https://rozitech.co.id/panduan-casir\n\nJika masih ada pertanyaan seputar penggunaan Casir, silakan hubungi CS kami 😊', 0, 0, 10, 2, 1, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(13, '4', '📍 INFO KANTOR & PEMBAYARAN', 'Informasi umum mengenai Rozitech:\n\n📍 Ketik *alamat* — Lokasi kantor kami\n💳 Ketik *cara bayar* — Info rekening & cara pembayaran', 1, 1, 1, 4, 1, 1, '2026-05-04 01:35:10', '2026-05-04 01:35:10'),
(14, 'alamat,lokasi,kantor,dimana,letak kantor', '📍 Alamat Kantor Pusat', '📍 Alamat Kantor Pusat Rozitech:\nJl. Raya Peganden, Leran, Manyar, Gresik, Jawa Timur.\n\n🗺️ Google Maps:\nhttps://maps.app.goo.gl/vhohZsCcaXWd2KxT8', 0, 0, 13, 1, 1, 1, '2026-05-04 01:35:10', '2026-05-06 03:58:14'),
(15, 'cara bayar,rekening,transfer,nomor rekening,bayar tagihan,pembayaran', '💳 Cara Bayar / Rekening', 'Untuk pembayaran layanan Rozitech, silakan transfer ke:\n\n🏦 BCA  : 7415234155 a.n Fachrur Rozi\n🏦 BRI  : 621001017663537 a.n Fachrur Rozi\n\n📸 *Wajib kirim bukti transfer setelah pembayaran nggih Kak* 🙏', 0, 0, 13, 2, 1, 1, '2026-05-04 01:35:10', '2026-05-04 01:35:10'),
(16, 'default', NULL, 'Halo, Saya R-Care 👋\nMaaf, saya kurang memahami maksud pesan Anda.\n\nKetik *menu* untuk melihat seluruh layanan resmi Rozitech ya Kak 😊', 0, 0, NULL, 99, 0, 1, '2026-05-04 01:35:10', '2026-05-18 04:00:00'),
(17, 'terima kasih,terimakasih,mkasih,mkch,mkcih,mkci,trims,makasiihh,makasi,makasih', NULL, 'Sama-sama Kak, senang bisa membantu 😊\nJika ada pertanyaan lain seputar layanan Rozitech, jangan ragu untuk menghubungi kami ya 🙏', 1, 0, NULL, 0, 1, 1, '2026-05-11 10:49:17', '2026-05-18 04:00:00'),
(18, 'kapan dipasang,jadwal pemasangan,belum dipasang,teknisi belum datang,progress pasang', '📅 Follow Up Jadwal Instalasi', 'Mohon maaf atas ketidaknyamanannya Kak 🙏\nKami bantu cek progres jadwal pemasangan Anda.\n\nMohon informasikan:\n📋 Nama pelanggan\n📞 Nomor yang terdaftar\n📍 Alamat pemasangan\n📅 Tanggal pengajuan sebelumnya\n\nTim kami akan segera konfirmasi jadwal teknisi 🔧', 0, 0, 2, 6, 1, 1, '2026-05-18 04:00:00', '2026-05-18 04:00:00'),
(19, 'internet lambat,wifi lemot,koneksi lambat,buffering,lemot,lambat', '🐢 Gangguan Internet Lambat', 'Mohon maaf atas kendala kecepatan yang dirasakan Kak 🙏\n\nUntuk penanganan yang tepat, kami perlu beberapa info:\n📋 ID pelanggan / nama terdaftar\n📡 Koneksi via WiFi atau kabel?\n📱 Apakah gangguan di semua perangkat atau hanya satu?\n📸 Bisa kirim hasil speed test dan foto lampu modem?\n\nSetelah dicek, kami akan bantu arahkan ke solusi terbaik 🔧', 0, 0, 2, 7, 1, 1, '2026-05-18 04:00:00', '2026-05-18 04:00:00'),
(20, 'cara restart modem,restart modem,reset wifi,cara matikan modem,nyalakan ulang modem', '🔄 Cara Restart Modem', 'Cara restart modem:\n\n1️⃣ Cabut adaptor modem dari stop kontak.\n2️⃣ Tunggu sekitar 30–60 detik.\n3️⃣ Sambungkan kembali adaptor ke listrik.\n4️⃣ Tunggu modem menyala normal (sekitar 2–3 menit).\n\nSetelah menyala, apakah lampu Power, PON, dan Internet sudah normal Kak? 😊\nJika masih bermasalah, mohon hubungi CS kami kembali 🙏', 0, 0, 2, 8, 1, 1, '2026-05-18 04:00:00', '2026-05-18 04:00:00'),
(21, 'lupa password wifi,sandi wifi,password wifi,ganti password wifi,password internet', '🔐 Lupa Password WiFi', 'Baik, kami bantu cek password WiFi Anda 🔐\n\nDemi keamanan akun, kami perlu verifikasi data pelanggan terlebih dahulu:\n📋 Nama pelanggan\n📍 Alamat pemasangan\n📞 Nomor terdaftar\n📌 Share ID pelanggan & lokasi\n\nJika ingin ganti password baru, sertakan juga password baru yang diinginkan ya Kak 😊', 0, 0, 2, 9, 1, 1, '2026-05-18 04:00:00', '2026-05-18 04:00:00'),
(22, 'tidak bisa connect wifi,wifi tidak muncul,gagal sambung wifi,tidak konek,wifi hilang,ssid tidak muncul', '📵 Tidak Bisa Connect WiFi', 'Baik, kami bantu pandu pengecekan koneksi perangkat Anda 😊\n\nMohon coba beberapa langkah ini:\n1️⃣ Apakah nama WiFi (SSID) muncul di perangkat Anda?\n2️⃣ Apakah kendala terjadi di satu perangkat atau semua perangkat?\n3️⃣ Sudah coba *Forget Network* lalu sambungkan ulang?\n\nJika SSID tidak muncul sama sekali atau semua perangkat gagal terhubung, mohon kirim foto lampu modem dan ID pelanggan agar kami eskalasikan ke tim teknis 🔧', 0, 0, 2, 10, 1, 1, '2026-05-18 04:00:00', '2026-05-18 04:00:00'),
(23, 'tagihan,bayar,invoice,jatuh tempo,nunggak,belum bayar,tagihan berapa', '💰 Info Tagihan', 'Baik, kami bantu cek informasi tagihan Anda 💳\n\nMohon informasikan:\n📋 Nama pelanggan atau ID pelanggan\n\nKami akan cek nominal tagihan dan status pembayaran Anda segera 😊\n\nAtau ketik *cek tagihan* diikuti ID pelanggan Anda.\nContoh: *cek tagihan aa20*', 0, 0, 2, 11, 1, 1, '2026-05-18 04:00:00', '2026-05-18 04:00:00'),
(24, 'komplain teknisi,teknisi lama,teknisi tidak datang,teknisi tidak sopan,lapor teknisi,protes teknisi', '😤 Komplain Layanan Teknisi', 'Mohon maaf atas pengalaman yang kurang menyenangkan Kak 🙏\nKami sangat menghargai setiap masukan demi peningkatan layanan.\n\nMohon informasikan:\n📋 Nama pelanggan & alamat\n📅 Tanggal & waktu kejadian\n📝 Kronologi singkat kejadian\n\nKeluhan Anda akan kami teruskan langsung ke supervisor dan koordinator lapangan kami 🙏', 0, 0, 2, 12, 1, 1, '2026-05-18 04:00:00', '2026-05-18 04:00:00'),
(25, 'sudah,selesai,normal,beres,oke,ok,sudah bisa,sudah normal', '✅ Konfirmasi Selesai', 'Alhamdulillah, senang mendengar masalahnya sudah teratasi Kak 😊\n\nJika suatu saat ada kendala lain terkait layanan Rozitech, jangan ragu untuk menghubungi kami kembali ya 🙏\n\nTerima kasih sudah menjadi pelanggan setia Rozitech! 🌟', 0, 0, NULL, 98, 1, 1, '2026-05-18 04:00:00', '2026-05-18 04:00:00'),
(26, 'integrasi facebook pixel', 'Advanced Website Features', 'Ya, kami akan pasang kode Facebook Pixel dan Google Ads (Conversion Tag) di website Kakak. Ini penting untuk optimasi iklan.', 0, 0, 7, 26, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(27, 'website multi vendor', 'Advanced Website Features', 'Website multi-vendor (seperti Tokopedia/Shopee) adalah custom system yang besar, Kak. Kami bisa buat, tapi memerlukan konsultasi fitur detail. (Ketik: tanya kebutuhan)', 0, 0, 7, 27, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(28, 'fitur reservasi', 'Advanced Website Features', 'Fitur reservasi online (booking) bisa kami buat, lengkap dengan kalender dan notifikasi otomatis. Ini termasuk fitur tambahan, Kak.', 0, 0, 7, 28, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(29, 'web cepat banget', 'Advanced Website Features', 'Kami akan optimalkan kecepatan website Kakak semaksimal mungkin, namun kecepatan akhir juga bergantung pada kualitas koneksi pengunjung.', 0, 0, 7, 29, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(30, 'web sudah termasuk email', 'Advanced Website Features', 'Tentu, Kak. Kami akan bantu setting email perusahaan (Contoh: info@domainkakak.com) yang bisa diakses via webmail atau aplikasi email Kakak.', 0, 0, 7, 30, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(31, 'website untuk klinik', 'Advanced Website Features', 'Website klinik biasanya butuh fitur pendaftaran online, jadwal dokter, dan artikel kesehatan. Kami siap buatkan yang profesional.', 0, 0, 7, 31, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(32, 'fitur chat bot', 'Advanced Website Features', 'Kami bisa pasang fitur chat bot sederhana di website Kakak (integrasi dengan platform pihak ketiga). Ini membantu merespon pertanyaan cepat.', 0, 0, 7, 32, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(33, 'ganti domain', 'Advanced Website Features', 'Perubahan nama domain setelah website jadi bisa kami bantu, Kak. Tapi ada biaya penggantian dan proses setting teknis yang perlu dilakukan.', 0, 0, 7, 33, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(34, 'upgrade hosting', 'Advanced Website Features', 'Jika trafik website Kakak sangat ramai, kami bisa bantu proses upgrade hosting ke server yang lebih kuat tanpa mengganggu layanan.', 0, 0, 7, 34, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(35, 'migrasi web lama', 'Advanced Website Features', 'Kami bisa bantu pindahkan (migrasi) website Kakak yang lama ke server kami. Kami akan cek teknisnya dulu, Kak, apakah ada biaya tambahan.', 0, 0, 7, 35, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(36, 'web pakai bahasa apa', 'Advanced Website Features', 'Kami menggunakan bahasa pemrograman terbaru yang aman dan cepat (misalnya: PHP/Laravel atau JS/React) untuk memastikan kualitas.', 0, 0, 7, 36, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(37, 'website harga 5 juta', 'Advanced Website Features', 'Website harga Rp 5 Juta biasanya sudah Toko Online lengkap atau Website Perusahaan dengan fitur yang cukup kompleks.', 0, 0, 7, 37, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(38, 'website harga 10 juta', 'Advanced Website Features', 'Website harga Rp 10 Juta ke atas biasanya sudah Custom System atau web portal besar yang memerlukan database dan fitur yang sangat spesifik.', 0, 0, 7, 38, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(39, 'fitur voucher diskon', 'Advanced Website Features', 'Fitur voucher dan diskon otomatis sudah termasuk di paket Toko Online kami. Kakak bisa atur kode dan masa berlakunya sendiri di CMS.', 0, 0, 7, 39, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(40, 'fitur dropship', 'Advanced Website Features', 'Kami bisa buatkan fitur dropship di toko online Kakak, di mana order akan otomatis diteruskan ke supplier Kakak. (Termasuk custom fitur).', 0, 0, 7, 40, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(41, 'aplikasi pakai ai', 'Advanced Application Features', 'Integrasi AI (Artificial Intelligence) pada aplikasi sangat mungkin, Kak. Contoh: fitur rekomendasi produk otomatis. Ini termasuk project kompleks.', 0, 0, 7, 41, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(42, 'fitur augmented reality', 'Advanced Application Features', 'Fitur Augmented Reality (AR) sangat menarik, Kak. Kami bisa buatkan, namun project ini memerlukan biaya dan waktu yang cukup besar.', 0, 0, 7, 42, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(43, 'aplikasi social media', 'Advanced Application Features', 'Aplikasi media sosial adalah project yang sangat besar (butuh server kuat, fitur real-time). Kami sarankan kita mulai dari niche/fitur tertentu dulu.', 0, 0, 7, 43, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(44, 'biaya upload app store', 'Advanced Application Features', 'Biaya upload ke App Store dan Play Store biasanya adalah biaya akun developer tahunan (sekitar $99/tahun), Kak. Biaya ini ditanggung Kakak.', 0, 0, 7, 44, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(45, 'butuh fitur fingerprint', 'Advanced Application Features', 'Ya, fitur fingerprint atau face ID bisa kami integrasikan untuk keamanan login aplikasi.', 0, 0, 7, 45, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(46, 'fitur login google', 'Advanced Application Features', 'Tentu, Kak. Kami bisa integrasikan login via Google, Facebook, atau akun media sosial lain, agar user Kakak mudah mendaftar.', 0, 0, 7, 46, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(47, 'integrasi printer kasir', 'Advanced Application Features', 'Aplikasi kasir kami bisa terintegrasi dengan printer thermal (Bluetooth atau LAN) untuk mencetak struk.', 0, 0, 7, 47, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(48, 'aplikasi e-commerce besar', 'Advanced Application Features', 'Untuk aplikasi e-commerce berskala besar (ribuan produk), kami akan siapkan arsitektur server yang sangat kuat. (Ketik: tanya kebutuhan)', 0, 0, 7, 48, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(49, 'aplikasi butuh maintenance bulanan', 'Advanced Application Features', 'Aplikasi yang kompleks memang disarankan mengambil paket maintenance bulanan untuk update keamanan, Kak. Biayanya bervariasi.', 0, 0, 7, 49, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(50, 'aplikasi untuk travel', 'Advanced Application Features', 'Aplikasi travel/perjalanan biasanya butuh booking, peta, dan ulasan. Fitur apa yang Kakak ingin tonjolkan?', 0, 0, 7, 50, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(51, 'aplikasi pakai barcode scanner', 'Advanced Application Features', 'Ya, fitur barcode scanner bisa kami integrasikan ke aplikasi Kakak (misalnya untuk manajemen inventaris atau kasir).', 0, 0, 7, 51, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(52, 'ganti logo aplikasi', 'Advanced Application Features', 'Perubahan logo atau warna aplikasi (branding) bisa kami lakukan sebelum rilis, Kak.', 0, 0, 7, 52, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(53, 'aplikasi android saja', 'Advanced Application Features', 'Fokus membuat Android saja bisa lebih cepat (sekitar 1-2 bulan) dan sedikit lebih hemat biaya. Apakah ini target utama Kakak?', 0, 0, 7, 53, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(54, 'aplikasi ios saja', 'Advanced Application Features', 'Jika Kakak hanya menargetkan pengguna iPhone (iOS) saja, kami juga bisa buatkan secara khusus.', 0, 0, 7, 54, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(55, 'fitur admin panel', 'Advanced Application Features', 'Admin panel (dashboard untuk mengelola aplikasi) sudah pasti kami sediakan di setiap project aplikasi custom.', 0, 0, 7, 55, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(56, 'janji manis', 'Detailed Objection Handling', 'Kami tidak menjual janji manis, Kak, kami menjual bukti. Kakak bisa lihat hasil kerja kami di portofolio, dan semua janji kami tuangkan dalam kontrak.', 0, 0, 7, 56, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(57, 'bisa bayar setelah jadi', 'Detailed Objection Handling', 'Mohon maaf, Kak. Kami tidak bisa. Kami butuh DP 50% di awal untuk modal operasional dan mengikat jadwal pengerjaan.', 0, 0, 7, 57, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(58, 'takut tidak ada support', 'Detailed Objection Handling', 'Kami menjamin support setelah serah terima, Kak. Ada garansi 1 bulan dan paket maintenance tahunan/bulanan yang bisa Kakak ambil.', 0, 0, 7, 58, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(59, 'saya mau ambil paket yang paling murah', 'Detailed Objection Handling', 'Baik, Kak. Paket paling murah adalah Landing Page (untuk web) atau Aplikasi Sederhana (untuk app). Kami akan buatkan estimasi harganya.', 0, 0, 7, 59, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(60, 'saya minta diskon 20 persen', 'Detailed Objection Handling', 'Kami sangat ingin membantu, Kak, tapi diskon 20% terlalu besar. Kami bisa berikan harga spesial bundling atau bonus fitur minor saja, ya.', 0, 0, 7, 60, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(61, 'coba gratis', 'Detailed Objection Handling', 'Kami tidak menyediakan coba gratis, Kak. Tapi kami bisa berikan demo desain dan prototype di awal agar Kakak punya gambaran sebelum DP.', 0, 0, 7, 61, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(62, 'saya mau bandingkan harga dengan 5 tempat', 'Detailed Objection Handling', 'Silakan, Kak {Nama Customer}. Kami yakin harga dan layanan kami bersaing. Kami tunggu Kakak kembali saat sudah punya keputusan yang mantap.', 0, 0, 7, 62, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(63, 'saya mau lihat tim developer', 'Detailed Objection Handling', 'Mohon maaf, Kak, untuk privasi, kami tidak bisa menampilkan semua tim developer. Tapi kami bisa perkenalkan Project Manager yang akan bertanggung jawab.', 0, 0, 7, 63, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(64, 'saya mau pikirkan 3 bulan', 'Detailed Objection Handling', 'Tidak masalah, Kak. Kami sarankan Kakak simpan nomor kami. Tapi perlu diingat, harga dan jadwal developer bisa berubah dalam 3 bulan.', 0, 0, 7, 64, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(65, 'saya takut proyek ditunda', 'Detailed Objection Handling', 'Kami menjamin pengerjaan tepat waktu selama Kakak menyediakan data (teks, foto) sesuai jadwal yang disepakati. Kami akan cantumkan di kontrak.', 0, 0, 7, 65, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(66, 'saya mau jaminan hasil', 'Detailed Objection Handling', 'Jaminan hasil adalah project sesuai dengan fitur yang tertulis di kontrak (SPK). Kami akan berikan trial (uji coba) sebelum pelunasan.', 0, 0, 7, 66, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(67, 'kenapa harus custom', 'Detailed Objection Handling', 'Custom lebih baik karena fitur dan desain 100% sesuai alur bisnis Kakak, tidak ada fitur yang tidak terpakai, dan lebih aman dari hack.', 0, 0, 7, 67, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(68, 'fitur ini harus ada', 'Detailed Objection Handling', 'Baik, Kak. Jika fitur itu wajib ada, kami akan masukkan ke proposal dan hitung biayanya. Kami prioritaskan fitur wajib Kakak.', 0, 0, 7, 68, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(69, 'saya sudah punya domain', 'Detailed Objection Handling', 'Bagus, Kak. Jika sudah punya domain, kami bisa kurangi biaya domain/hosting di tahun pertama dari total tagihan Kakak.', 0, 0, 7, 69, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(70, 'apa syarat & ketentuan', 'Detailed Objection Handling', 'Syarat dan Ketentuan akan terlampir lengkap di Surat Kontrak Kerjasama (SPK) yang akan kami kirimkan. Intinya, transparan dan mengikat.', 0, 0, 7, 70, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(71, 'proses kontrak', 'Contract Payment Support Details', 'Proses kontrak sangat mudah: Kakak review SPK (Surat Perjanjian), jika setuju, tanda tangan dan bayar DP. Project langsung dimulai.', 0, 0, 7, 71, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(72, 'detail denda', 'Contract Payment Support Details', 'Denda hanya berlaku jika Kakak membatalkan project secara sepihak setelah DP dibayar, atau jika pelunasan melewati batas waktu yang disepakati.', 0, 0, 7, 72, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(73, 'garansi setelah 1 bulan', 'Contract Payment Support Details', 'Setelah masa garansi 1 bulan habis, Kakak bisa ambil paket maintenance bulanan/tahunan kami. Jika tidak, biaya perbaikan akan dihitung per kasus.', 0, 0, 7, 73, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(74, 'cara perpanjangan tahunan', 'Contract Payment Support Details', 'Kami akan ingatkan Kakak 1 bulan sebelum jatuh tempo perpanjangan domain/hosting. Kakak tinggal bayar tagihan tahunan tersebut.', 0, 0, 7, 74, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(75, 'apa yang saya dapatkan', 'Contract Payment Support Details', 'Kakak akan mendapatkan: Website/Aplikasi yang berfungsi, File master (source code), Akun CMS/Admin Panel, dan Garansi 1 bulan.', 0, 0, 7, 75, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(76, 'saya mau source code', 'Contract Payment Support Details', 'Tentu, Kak. Source code (kode sumber) project adalah hak milik Kakak setelah pelunasan 100%. Kami akan serahkan semuanya.', 0, 0, 7, 76, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(77, 'perjanjian kerahasiaan', 'Contract Payment Support Details', 'Kami sangat menjunjung tinggi kerahasiaan. Perjanjian NDA (Non-Disclosure Agreement) bisa kami sertakan di awal.', 0, 0, 7, 77, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(78, 'bukti transfer', 'Contract Payment Support Details', 'Bukti transfer harus berupa foto/screenshot yang jelas, dikirim ke Admin Billing kami, agar pembayaran Kakak bisa segera diverifikasi.', 0, 0, 7, 78, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(79, 'kapan invoice dikirim', 'Contract Payment Support Details', 'Invoice DP kami kirim segera setelah Kakak konfirmasi nama dan email. Invoice pelunasan kami kirim setelah project selesai 100%.', 0, 0, 7, 79, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(80, 'kontak support', 'Contract Payment Support Details', 'Kontak support teknis akan Kakak dapatkan setelah project diserahkan. Ada nomor khusus untuk pelaporan bug/error.', 0, 0, 7, 80, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(81, 'perbaikan bug', 'Contract Payment Support Details', 'Perbaikan bug atau error minor selama 1 bulan masa garansi tidak dikenakan biaya.', 0, 0, 7, 81, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(82, 'biaya migrasi', 'Contract Payment Support Details', 'Biaya migrasi (perpindahan server) akan kami infokan setelah kami cek kompleksitas data dan file yang akan dipindah.', 0, 0, 7, 82, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(83, 'jika saya mau tambah fitur', 'Contract Payment Support Details', 'Penambahan fitur setelah kontrak berjalan akan dibuatkan addendum (kontrak tambahan) baru, lengkap dengan biaya dan waktu pengerjaan.', 0, 0, 7, 83, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(84, 'pembayaran bertahap', 'Contract Payment Support Details', 'Pembayaran standar kami 50% DP dan 50% Pelunasan. Untuk project yang sangat besar (di atas 50 juta), pembayaran bertahap bisa didiskusikan.', 0, 0, 7, 84, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(85, 'apa itu spk', 'Contract Payment Support Details', 'SPK adalah Surat Perjanjian Kerjasama. Ini dokumen legal yang mengikat komitmen kami dan Kakak.', 0, 0, 7, 85, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(86, 'fu 14 hari', 'Follow Up Re-engagement', 'Halo Kak {Nama Customer}. Bagaimana perkembangan bisnis Kakak? Apakah sudah ada waktu luang untuk mendiskusikan proposal kami lagi?', 0, 0, 7, 86, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(87, 'fu 3 minggu', 'Follow Up Re-engagement', 'Selamat siang, Bapak/Ibu {Nama Customer}. Kami mohon maaf mengganggu, kami hanya ingin memastikan rencana project Kakak. Kami tunggu kabar baiknya ya.', 0, 0, 7, 87, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(88, 'fu 2 bulan', 'Follow Up Re-engagement', 'Halo, Kak. Kami kebetulan punya slot developer yang baru selesai. Apakah project Kakak sudah siap dimulai bulan ini? Kami siap membantu.', 0, 0, 7, 88, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(89, 'follow up tidak memaksa', 'Follow Up Re-engagement', 'Kami hanya mengingatkan dengan sopan, Kak {Nama Customer}. Kami tidak memaksa, hanya memastikan Kakak tidak kehilangan kesempatan terbaik.', 0, 0, 7, 89, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(90, 'kapan kita bisa ngobrol', 'Follow Up Re-engagement', 'Kapan Kakak ada waktu 15 menit untuk video call/telepon? Kami ingin memastikan semua poin sudah jelas di proposal.', 0, 0, 7, 90, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(91, 'saya sudah terima penawaran', 'Follow Up Re-engagement', 'Baik, Kak {Nama Customer}. Apakah ada bagian yang Kakak rasa kurang jelas di penawaran tersebut? Silakan tanyakan pada saya.', 0, 0, 7, 91, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(92, 'saya sedang sibuk', 'Follow Up Re-engagement', 'Kami paham, Kak. Silakan kabari kapan waktu yang tepat agar kami bisa menghubungi kembali. Kami fleksibel.', 0, 0, 7, 92, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(93, 'saya lupa penawarannya', 'Follow Up Re-engagement', 'Tidak masalah, Kak. Saya akan kirim ulang proposal penawaran ke email/WA Kakak. Mohon dicek.', 0, 0, 7, 93, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(94, 'follow up akhir tahun', 'Follow Up Re-engagement', 'Di akhir tahun ini, kami ada penawaran khusus. Mungkin ini waktu yang tepat untuk Kakak memulai project. Tertarik, Kak?', 0, 0, 7, 94, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(95, 'follow up harga naik', 'Follow Up Re-engagement', 'Mohon maaf, Kak. Karena harga material/layanan naik, penawaran kami akan naik di bulan depan. Jika deal sekarang, Kakak masih dapat harga lama.', 0, 0, 7, 95, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(96, 'jam operasional', 'General Fallback Greeting Extensions', 'Jam operasional admin kami adalah Senin-Jumat, pukul 09.00 - 17.00 WIB. Di luar jam itu, saya akan bantu jawab pertanyaan umum Kakak.', 0, 0, NULL, 96, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(97, 'alamat email resmi', 'General Fallback Greeting Extensions', 'Alamat email resmi kami untuk korespondensi: [Email Resmi Perusahaan].', 0, 0, NULL, 97, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(98, 'saya mau komplain', 'General Fallback Greeting Extensions', 'Mohon maaf sekali, Kak. Jika ada keluhan, silakan ketik: bicara admin, dan kami akan alihkan ke tim CS kami yang berwenang.', 0, 0, NULL, 98, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(99, 'apakah bisa kerjasama', 'General Fallback Greeting Extensions', 'Kami terbuka untuk kerjasama, Kak. Boleh jelaskan detail kerjasama apa yang Kakak maksud?', 0, 0, NULL, 99, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(100, 'saya mau jadi reseller', 'General Fallback Greeting Extensions', 'Tentu, Kak. Kami memiliki program reseller. Silakan ketik: bicara admin, dan kami akan alihkan ke Admin Partnership kami.', 0, 0, NULL, 100, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(101, 'apa nama anda', 'General Fallback Greeting Extensions', 'Nama saya R-Care, Admin AI dari [Nama Perusahaan]. Saya siap membantu konsultasi awal Kakak.', 0, 0, NULL, 101, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(102, 'terima kasih kembali', 'General Fallback Greeting Extensions', 'Sama-sama, Kak {Nama Customer}. Semoga sukses selalu untuk Kakak.', 0, 0, NULL, 102, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(103, 'bagaimana cara saya panggil anda', 'General Fallback Greeting Extensions', 'Panggil saya R-Care, Kak. Atau jika Kakak sudah memberikan nama, saya akan panggil Kakak dengan sebutan Bapak/Ibu {Nama Customer} yang sopan.', 0, 0, NULL, 103, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(104, 'apa itu developer', 'General Fallback Greeting Extensions', 'Developer adalah tim ahli kami yang bertugas membuat kode dan merancang sistem website/aplikasi Kakak.', 0, 0, NULL, 104, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(105, 'saya tidak punya logo', 'General Fallback Greeting Extensions', 'Tidak masalah, Kak. Kami bisa bantu rekomendasi desainer logo profesional yang bisa Kakak gunakan.', 0, 0, NULL, 105, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(106, 'saya butuh segera', 'General Fallback Greeting Extensions', 'Jika butuh segera, kami akan fokus pada fitur MVP dan desain standar agar rilis cepat. Ada biaya fast track untuk percepatan, Kak.', 0, 0, NULL, 106, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(107, 'selamat hari libur', 'General Fallback Greeting Extensions', 'Selamat hari libur juga, Kak. Meskipun libur, saya (R-Care) tetap siap melayani pertanyaan Kakak.', 0, 0, NULL, 107, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(108, 'pertanyaan umum', 'General Fallback Greeting Extensions', 'Pertanyaan umum seputar layanan kami: harga, fitur, atau lama pengerjaan. Kakak mau tanya yang mana?', 0, 0, NULL, 108, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(109, 'tolong ulangi', 'General Fallback Greeting Extensions', 'Maaf, Kak. Bagian mana yang perlu saya ulangi? (Contoh: Ulangi harga app)', 0, 0, NULL, 109, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(110, 'web dan app custom', 'General Fallback Greeting Extensions', 'Kami spesialis di website dan aplikasi custom, yang berarti semua fitur dirancang khusus sesuai kebutuhan bisnis Kakak.', 0, 0, NULL, 110, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(111, 'saya sudah punya desain', 'General Fallback Greeting Extensions', 'Bagus, Kak. Jika sudah ada desain, itu mempercepat proses. Kami hanya perlu tahap slicing (mengubah desain menjadi kode).', 0, 0, NULL, 111, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(112, 'saya sudah punya wireframe', 'General Fallback Greeting Extensions', 'Wireframe sangat membantu! Itu akan menjadi panduan teknis kami. Mari kita diskusikan alur wireframe Kakak.', 0, 0, NULL, 112, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(113, 'cara bayar lunas', 'General Fallback Greeting Extensions', 'Pembayaran lunas dilakukan setelah Kakak setuju dengan hasil demo, sebelum kami serahkan file dan launching secara publik.', 0, 0, NULL, 113, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(114, 'harga paket bundling', 'General Fallback Greeting Extensions', 'Harga paket bundling adalah harga khusus untuk order Website dan Aplikasi sekaligus. Jauh lebih hemat, Kak. (Ketik: minta penawaran)', 0, 0, NULL, 114, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(115, 'ada harga khusus', 'General Fallback Greeting Extensions', 'Ya, harga khusus kami berikan untuk paket bundling atau project dengan fitur yang sangat sederhana (MVP).', 0, 0, NULL, 115, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(116, 'selamat pagi,pagi', 'Pembuka Percakapan Lanjutan', 'Selamat pagi, Kak! Ada yang bisa saya bantu terkait jasa pembuatan website atau aplikasi?', 0, 0, NULL, 116, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(117, 'permisi,halo', 'Pembuka Percakapan Lanjutan', 'Halo, selamat datang di layanan kami. Saya R-Care. Silakan sampaikan kebutuhan Kakak.', 0, 0, NULL, 117, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(118, 'mau buat,bikin', 'Pembuka Percakapan Lanjutan', 'Kakak mau buat Website atau Aplikasi? Kami spesialis di custom development.', 0, 0, NULL, 118, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(119, 'harga,biaya', 'Pembuka Percakapan Lanjutan', 'Untuk harga, Kakak mau tahu harga Website atau Aplikasi? (Ketik: harga web / harga app)', 0, 0, NULL, 119, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(120, 'mau buat website toko', 'Pembuka Percakapan Lanjutan', 'Tentu, Toko Online kami bisa dilengkapi fitur manajemen produk, order, dan pembayaran. Mau tahu estimasi harganya?', 0, 0, NULL, 120, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(121, 'mau buat aplikasi kasir', 'Pembuka Percakapan Lanjutan', 'Aplikasi kasir (POS) adalah salah satu layanan unggulan kami. Apakah Kakak butuh integrasi stok barang juga?', 0, 0, NULL, 121, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(122, 'berapa biaya web company profile', 'Pembuka Percakapan Lanjutan', 'Website Company Profile mulai dari Rp 1.5 Juta hingga Rp 3 Juta, Kak, tergantung jumlah halaman dan desain.', 0, 0, NULL, 122, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(123, 'berapa biaya aplikasi sederhana', 'Pembuka Percakapan Lanjutan', 'Aplikasi yang fokus pada 1-2 fitur sederhana, biayanya mulai dari Rp 5 Juta. Ini untuk aplikasi Android saja.', 0, 0, NULL, 123, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(124, 'lama pengerjaan toko online', 'Pembuka Percakapan Lanjutan', 'Pengerjaan Toko Online standar butuh waktu 10-14 hari kerja, setelah semua data dari Kakak lengkap.', 0, 0, NULL, 124, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(125, 'lama pengerjaan aplikasi', 'Pembuka Percakapan Lanjutan', 'Untuk aplikasi custom, estimasi waktu pengerjaan kami sekitar 1-3 bulan, tergantung kompleksitas fiturnya.', 0, 0, NULL, 125, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(126, 'fitur web yang paling penting', 'Konsultasi Fitur Wajib', 'Fitur paling penting adalah desain responsive (mobile friendly), CMS yang mudah, dan keamanan dasar (SSL). Semua sudah termasuk.', 0, 0, NULL, 126, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(127, 'fitur app yang paling penting', 'Konsultasi Fitur Wajib', 'Fitur wajib aplikasi adalah user experience (UI/UX) yang bagus, notifikasi, dan admin panel yang stabil.', 0, 0, NULL, 127, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(128, 'konsultasi dulu', 'Konsultasi Fitur Wajib', 'Tentu, Kak. Agar konsultasinya maksimal, boleh saya tahu nama usahanya dan target pasar yang ingin dicapai?', 0, 0, NULL, 128, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(129, 'saya mau tanya budget', 'Konsultasi Fitur Wajib', 'Baik, Kak. Untuk kisaran budget, apakah Kakak sudah menyiapkan dana di atas atau di bawah Rp 5 Juta? Ini akan membantu kami menyarankan fitur yang realistis.', 0, 0, NULL, 129, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(130, 'tidak ada dana,belum ada modal', 'Konsultasi Fitur Wajib', 'Kami paham, Kak. Jika dananya belum siap, silakan Kakak kabari kami lagi. Kami siap membantu kapanpun.', 0, 0, NULL, 130, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(131, 'harga mahal sekali', 'Konsultasi Fitur Wajib', 'Kami menawarkan kualitas dan garansi, Kak. Harga kami sebanding dengan hasil profesional dan support jangka panjang. Apakah kita perlu mengurangi beberapa fitur?', 0, 0, NULL, 131, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(132, 'takut tidak sesuai harapan', 'Konsultasi Fitur Wajib', 'Kami akan buatkan desain awal (prototype) untuk Kakak setujui. Jika ada yang kurang, kita revisi dulu di tahap desain. Kami jamin hasilnya sesuai yang disepakati.', 0, 0, NULL, 132, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(133, 'mau lihat contoh web', 'Konsultasi Fitur Wajib', 'Tentu, Kak. Kakak bisa lihat portofolio website kami di [Link Portofolio]. Silakan dilihat-lihat dulu ya.', 0, 0, NULL, 133, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(134, 'mau lihat contoh app', 'Konsultasi Fitur Wajib', 'Kami akan kirimkan beberapa contoh demo aplikasi yang pernah kami buat, Kak. Mohon tunggu sebentar.', 0, 0, NULL, 134, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(135, 'saya tertarik', 'Konsultasi Fitur Wajib', 'Senang mendengarnya, Kak! Sebelum lanjut ke kontrak, boleh saya tahu nama lengkap Bapak/Ibu/Kakak dan alamat email yang aktif?', 0, 0, NULL, 135, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(136, 'mau lanjut order', 'Closing Action Steps', 'Siap, Bapak/Ibu {Nama Customer}. Tim kami akan segera membuatkan proposal dan invoice DP (50%) untuk memulai project.', 0, 0, NULL, 136, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(137, 'minta proposal', 'Closing Action Steps', 'Proposal akan kami kirimkan ke email Bapak/Ibu {Nama Customer}. Mohon tunggu 1x24 jam untuk detail harga dan fitur yang sudah kita diskusikan.', 0, 0, NULL, 137, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(138, 'kirim detail harga', 'Closing Action Steps', 'Rincian detail harga akan kami kirim dalam bentuk proposal resmi ke email Kakak. Apakah email yang ini sudah benar? {Email Customer}', 0, 0, NULL, 138, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(139, 'kapan dp harus dibayar', 'Closing Action Steps', 'DP 50% harus dibayar setelah Kakak menerima dan menyetujui Surat Kontrak Kerjasama (SPK) dari kami.', 0, 0, NULL, 139, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(140, 'apakah ada jaminan', 'Closing Action Steps', 'Ya, kami memberikan jaminan perbaikan bug/error selama 1 bulan penuh setelah serah terima project.', 0, 0, NULL, 140, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(141, 'apa itu source code', 'Closing Action Steps', 'Source code adalah file asli dari website/aplikasi Kakak. File ini adalah hak milik Kakak sepenuhnya setelah pelunasan.', 0, 0, NULL, 141, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(142, 'boleh lihat demo', 'Closing Action Steps', 'Kami bisa tunjukkan demo prototype desain sebelum proses coding, Kak. Ini untuk memastikan desain sesuai keinginan Kakak.', 0, 0, NULL, 142, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(143, 'kenapa harus dp', 'Closing Action Steps', 'DP diperlukan untuk: 1. Pembelian lisensi/domain/hosting, dan 2. Mengunci jadwal developer kami khusus untuk project Kakak.', 0, 0, NULL, 143, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(144, 'kapan mulai kerja', 'Closing Action Steps', 'Pengerjaan akan dimulai maksimal 1 hari kerja setelah DP 50% kami terima dan Kakak telah melengkapi data awal.', 0, 0, NULL, 144, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(145, 'saya mau buat web perusahaan', 'Closing Action Steps', 'Website Perusahaan (Company Profile) adalah pilihan tepat untuk kredibilitas. Fitur apa yang Kakak anggap wajib ada di halaman utama?', 0, 0, NULL, 145, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(146, 'saya mau buat aplikasi pendidikan', 'Pertanyaan Spesifik Lanjutan', 'Aplikasi pendidikan butuh fitur absensi, materi, dan kuis. Kami akan buatkan sistem yang mudah digunakan oleh guru dan siswa.', 0, 0, NULL, 146, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(147, 'web sudah termasuk seo', 'Pertanyaan Spesifik Lanjutan', 'Kami berikan SEO dasar (optimasi kecepatan & struktur kode). Untuk SEO yang lebih agresif (naik ke halaman 1), kami punya paket tambahan.', 0, 0, NULL, 147, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(148, 'aplikasi bisa di-update', 'Pertanyaan Spesifik Lanjutan', 'Tentu, Kak. Aplikasi yang kami buat didesain agar mudah di-update (via Play Store/App Store) jika ada penambahan fitur di masa depan.', 0, 0, NULL, 148, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(149, 'apakah ada biaya bulanan', 'Pertanyaan Spesifik Lanjutan', 'Website hanya ada biaya perpanjangan tahunan. Aplikasi bisa ada biaya bulanan jika Kakak ambil paket maintenance atau sewa server khusus.', 0, 0, NULL, 149, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(150, 'saya mau bicara dengan sales', 'Pertanyaan Spesifik Lanjutan', 'Baik, Kak. Saya akan alihkan chat Kakak ke Admin Sales kami yang sedang bertugas. Mohon tunggu sebentar ya.', 0, 0, NULL, 150, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(151, 'saya mau buat web dan app sekaligus', 'Pertanyaan Spesifik Lanjutan', 'Ini sangat baik, Kak. Kami bisa integrasikan keduanya (satu database). Kami akan berikan harga paket bundling yang lebih hemat.', 0, 0, NULL, 151, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(152, 'apa perbedaan web dan landing page', 'Pertanyaan Spesifik Lanjutan', 'Website punya banyak halaman (menu), Landing Page hanya 1 halaman, fokus pada promosi. Landing Page lebih murah.', 0, 0, NULL, 152, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(153, 'saya akan pikirkan', 'Pertanyaan Spesifik Lanjutan', 'Silakan, Kak {Nama Customer}. Kami tidak terburu-buru. Kami siap menjawab pertanyaan susulan kapan pun.', 0, 0, NULL, 153, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(154, 'saya akan kabari lagi minggu depan', 'Pertanyaan Spesifik Lanjutan', 'Baik, Kak. Saya catat untuk follow up minggu depan. Sukses selalu untuk usahanya.', 0, 0, NULL, 154, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(155, 'saya butuh nomor rekening', 'Pertanyaan Spesifik Lanjutan', 'Nomor rekening resmi kami adalah [Daftar Rekening]. Mohon konfirmasi kembali setelah transfer ya.', 0, 0, NULL, 155, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(156, 'kenapa harganya berbeda beda', 'Final Negotiation Closing', 'Harga berbeda karena fitur, kompleksitas desain, dan waktu pengerjaan setiap project custom itu berbeda-beda, Kak.', 0, 0, NULL, 156, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(157, 'saya mau web yang simple', 'Final Negotiation Closing', 'Website simple kami sarankan Company Profile 3-5 halaman saja. Cepat jadi dan mudah dikelola.', 0, 0, NULL, 157, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(158, 'saya mau aplikasi yang banyak fitur', 'Final Negotiation Closing', 'Aplikasi dengan banyak fitur akan memerlukan waktu pengerjaan yang lebih lama (sekitar 3-5 bulan) dan biaya yang lebih besar.', 0, 0, NULL, 158, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(159, 'apakah saya harus menyediakan konten', 'Final Negotiation Closing', 'Ya, Kak. Konten (teks, foto, deskripsi) harus Kakak sediakan, karena hanya Kakak yang paling tahu detail bisnisnya.', 0, 0, NULL, 159, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(160, 'kapan saya harus melunasi', 'Final Negotiation Closing', 'Pelunasan dilakukan setelah Kakak setuju dengan hasil project (demo) dan puas, sebelum kami launching secara publik.', 0, 0, NULL, 160, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(161, 'apakah bisa revisi design', 'Final Negotiation Closing', 'Revisi design (sebelum coding) bisa dilakukan 1-2 kali agar sesuai ekspektasi Kakak. Setelah coding, revisi hanya minor.', 0, 0, NULL, 161, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(162, 'saya mau buat aplikasi untuk internal hrd', 'Final Negotiation Closing', 'Aplikasi HRD internal memerlukan fitur absensi, manajemen cuti, dan slip gaji. Kami bisa buatkan yang terintegrasi.', 0, 0, NULL, 162, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(163, 'bagaimana cara melihat progress', 'Final Negotiation Closing', 'Kami akan berikan akses ke staging link (link uji coba) agar Kakak bisa memantau progres website/aplikasi kapan saja.', 0, 0, NULL, 163, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(164, 'terima kasih atas info detailnya', 'Final Negotiation Closing', 'Sama-sama, Bapak/Ibu {Nama Customer}. Semoga informasinya membantu. Siap untuk lanjut order? (Ketik: mau order)', 0, 0, NULL, 164, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46'),
(165, 'saya mau selesai chat', 'Final Negotiation Closing', 'Terima kasih banyak, Kak {Nama Customer}. Kami tutup sesi chat ini. Selamat beraktivitas!', 0, 0, NULL, 165, 1, 1, '2026-05-18 05:10:46', '2026-05-18 05:10:46');
